const parse = $('Commit-Message aufbereiten').item.json;
const lookup = $('Linear Vorfall suchen').item.json;
const linearDone = $('Linear auf Erledigt setzen').item.json;
const notion = $('Notion PARA-Hub Kommentar').item.json;

const linearUuid = lookup?.data?.issues?.nodes?.[0]?.id;
const linearLookupOk = !!linearUuid;
const linearUpdateOk = linearDone?.data?.issueUpdate?.success === true;
const notionOk = !!(notion?.id || notion?.object === 'comment');

return {
  json: {
    issueId: parse.issueId,
    beschreibung: parse.description,
    linear_lookup_ok: linearLookupOk,
    linear_update_ok: linearUpdateOk,
    notion_kommentar_ok: notionOk,
    nachricht: 'Rueckkanal fuer ' + parse.issueId + ': Linear ' + (linearUpdateOk ? 'Done' : 'nicht gesetzt') + ', Notion ' + (notionOk ? 'ok' : 'fehlgeschlagen')
  }
};

// GitHub Push normalisieren (Webhook mit body / Trigger mit flachem JSON / body als String)
function normalizePushPayload(json) {
  let root = json;
  if (json.body !== undefined && json.body !== null) {
    if (typeof json.body === 'string') {
      try {
        root = JSON.parse(json.body);
      } catch {
        root = {};
      }
    } else {
      root = json.body;
    }
  }
  let commits = Array.isArray(root.commits) ? root.commits : [];
  if (commits.length === 0 && root.head_commit && root.head_commit.message) {
    commits = [root.head_commit];
  }
  return { commits, repository: root.repository };
}

const items = $input.all();
const results = [];
const regex = /\[BER-(\d+)\]\s*done:?\s*([\s\S]*)/i;

for (const item of items) {
  const { commits, repository } = normalizePushPayload(item.json);

  for (const commit of commits) {
    const message = commit.message || '';
    if (message.includes('Auto-Backup:')) continue;
    const match = message.match(regex);

    if (match) {
      const descRaw = (match[2] || '').trim();
      const description = descRaw.split(/\r?\n/)[0].trim();
      results.push({
        json: {
          issueNumber: parseInt(match[1], 10),
          issueId: 'BER-' + match[1],
          description,
          commitSha: (commit.id || commit.sha || '').substring(0, 8),
          commitUrl: commit.url || '',
          author: commit.author?.name || commit.author?.username || 'unknown',
          timestamp: commit.timestamp || new Date().toISOString(),
          matched: true,
          repository: repository?.full_name || '',
        },
      });
    }
  }
}

if (results.length === 0) {
  results.push({ json: { matched: false } });
}

return results;
